const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('middle-math/exercise-library.json'\)\);
// High-value alias candidates: look for exercises with common gym slang names
const aliasSignals = [
  'Deadlift', 'Squat', 'Bench', 'Press', 'Row', 'Curl', 'Extension', 'Fly',
  'Clean', 'Snatch', 'Jerk', 'Pullup', 'Pull-up', 'Pushup', 'Push-up', 'Dip',
  'Lunge', 'Hip Thrust', 'Shrug', 'Raise', 'Pulldown'
];
for \(const term of aliasSignals.slice\(0, 5\)\) {
  const matches = data.filter\(e => e.name.toLowerCase\(\).includes\(term.toLowerCase\(\)\)\);
  console.log\(term + ':', matches.length, 'entries. Examples:', matches.slice\(0, 3\).map\(e => e.name\)\);
}
// Count exercises by section
const bySect = {};
for \(const e of data\) {
  bySect[e.section] = \(bySect[e.section] || 0\) + 1;
}
console.log\('Exercises by section:', bySect\);
" 2>&1)

